42	// Swizzle Q tile and H tile to improve L2 cache hit rate, 
43	// and launch the longest main loop first to keep most SMs busy.
44	
45	struct CausalIndividualTileScheduler {
46	  
47	  static constexpr int TileQ = 16;
48	  static constexpr int TileH = 8;
49	  static constexpr int TileSize = TileQ * TileH;
50	
51	  struct Params {
52	    dim3 grid;
53	    int tile_max_q;
54	    FastDivmod divmod_tile_col;
55	    FastDivmod divmod_tile_size;
56	    FastDivmod divmod_tile_head;
57	  };
58	
59	  bool valid_ = true;
60	  Params params;
61	
62	  CUTLASS_DEVICE
63	  CausalIndividualTileScheduler(Params const& params) : params(params) {}
64	
65	  template<class ProblemSize, class ClusterShape, class TileShape>
66	  static Params to_underlying_arguments(
67	      ProblemSize const& problem_size, KernelHardwareInfo hw_info,
68	      ClusterShape const& cluster_shape, TileShape const& tile_shape) {
69	    using namespace cute;
70	
71	    dim3 grid(size<3,0>(problem_size), round_up(ceil_div(size<0>(problem_size), size<0>(tile_shape)), size<0>(cluster_shape)), size<3,1>(problem_size));
72	    // gridDim.x must multiple of TileH
73	    const int tile_col_count = grid.x / TileH;
74	    const int tile_max_q = grid.y / TileQ * TileQ;
75	    return Params{ grid , tile_max_q, tile_col_count, TileSize, TileH};
76	  }
77	
78	  static dim3 get_grid_shape(Params const& params) {
79	    return params.grid;
80	  }
81	
82	  CUTLASS_DEVICE
83	  bool is_valid() {
84	    return valid_;
85	  }
86	
87	  CUTLASS_DEVICE
88	  auto get_block_coord() {
89	    using namespace cute;
90	    const int block_idx = blockIdx.y * gridDim.x + blockIdx.x;
91	
92	    int tile_idx, tile_tail;
93	    params.divmod_tile_size(tile_idx, tile_tail, block_idx);
94	
95	    int tile_row_idx, tile_col_idx;
96	    params.divmod_tile_col(tile_row_idx,tile_col_idx, tile_idx);
97	
98	    int row_offset_in_tail, col_offset_in_tail;
99	    params.divmod_tile_head(row_offset_in_tail,col_offset_in_tail, tile_tail);
100	
101	    const int row_idx = tile_row_idx * TileQ + row_offset_in_tail;
102	    const int col_idx = tile_col_idx * TileH + col_offset_in_tail;
103	    
104	    // last q tile launch first
105	    if(blockIdx.y >= params.tile_max_q) {
106	      return make_coord(int(gridDim.y - 1 - blockIdx.y), _0{}, make_coord(int(blockIdx.x), int(blockIdx.z)));
107	    } 
108	
109	    return make_coord(int(gridDim.y) - 1 - row_idx, _0{}, make_coord(col_idx, int(blockIdx.z)));
110	  }
111	
112	  CUTLASS_DEVICE
113	  CausalIndividualTileScheduler& operator++() {
114	    valid_ = false;
115	    return *this;
116	  }
117	};
