143	  static Params to_underlying_arguments(
144	      ProblemSize const& problem_size, KernelHardwareInfo hw_info,
145	      ClusterShape const& cluster_shape, TileShape const& tile_shape) {
146	    using namespace cute;
147	    // Get SM count if needed, otherwise use user supplied SM count
