159	    int num_blocks = num_m_blocks * size<3,0>(problem_size) * size<3,1>(problem_size);
160	
161	    return Params {
162	      num_blocks,
163	      { size<3,0>(problem_size) }, { max(1, num_m_blocks) }, { size<3,1>(problem_size) },
164	      hw_info
165	    };
166	  }
167	
168	  static dim3 get_grid_shape(Params const& params) {
169	    dim3 grid(std::min(params.num_blocks, params.hw_info.sm_count), 1, 1);
170	    return grid;
171	  }
172	
173	  CUTLASS_DEVICE
174	  bool is_valid() {
175	    return block_idx < params.num_blocks;
176	  }
177	
178	  CUTLASS_DEVICE
179	  auto get_block_coord() {
180	    using namespace cute;
181	    int block_decode = block_idx;
182	    int m_block, bidb, bidh;
