222	  template <class Options>
223	  void run(const Options &options, const cutlass::KernelHardwareInfo &hw_info, at::Tensor q,
224	           at::Tensor k, at::Tensor v, at::Tensor o, at::Tensor lse, float scale_softmax,
225	           at::Tensor workspace, at::Tensor cumulative_seqlen_q,
226	           at::Tensor cumulative_seqlen_kv, int max_seqlen_q, int max_seqlen_kv) {
227	
228	    int total_seqlen_q = q.size(0);
229	    int total_seqlen_kv = k.size(0);
230	
231	    ProblemShapeType problem_shape =
232	        initialize(options, max_seqlen_q, max_seqlen_kv, total_seqlen_q, total_seqlen_kv,
233	                        cumulative_seqlen_q.data_ptr(), cumulative_seqlen_kv.data_ptr());
234	    
235	    int SQ = size<0>(problem_shape);
236	    int SK = size<1>(problem_shape);
237	    int B = size<3, 1>(problem_shape);
238	    int H = size<3, 0>(problem_shape);
239	    int H_K = size<3, 0, 1>(problem_shape);
240	    int H_Q = size<3, 0, 0>(problem_shape);
241	
242	    int q_stride0 = q.stride(0), q_stride1 = q.stride(1), q_stride2 = q.stride(2);
243	    int k_stride0 = k.stride(0), k_stride1 = k.stride(1), k_stride2 = k.stride(2);
244	    int v_stride0 = v.stride(0), v_stride1 = v.stride(1), v_stride2 = v.stride(2);
245	    int o_stride0 = o.stride(0), o_stride1 = o.stride(1), o_stride2 = o.stride(2);
246	    int lse_stride0 = lse.stride(0), lse_stride1 = lse.stride(1);
247	    TORCH_CHECK(q_stride2 == 1);
248	    TORCH_CHECK(k_stride2 == 1);
249	    TORCH_CHECK(v_stride2 == 1);
250	    TORCH_CHECK(o_stride2 == 1);
251	    TORCH_CHECK(lse_stride0 == 1);
252	
253	    stride_Q = make_stride(q_stride0, _1{}, make_stride(make_stride(q_stride1, H_Q * q_stride1), SQ * q_stride0));
254	    stride_O = make_stride(o_stride0, _1{}, make_stride(make_stride(o_stride1, H_Q * o_stride1), SQ * o_stride0));
255	    stride_K = make_stride(k_stride0, _1{}, make_stride(make_stride(_0{}, k_stride1), SK * k_stride0));
256	    stride_V = make_stride(v_stride0, _1{}, make_stride(make_stride(_0{}, v_stride1), SK * v_stride0));
257	    stride_LSE = make_stride(_1{}, make_stride(make_stride(lse_stride1, lse_stride1 * H_Q), SQ));
258	
259	    if constexpr (kIsVarlen) {
260	      get<2, 1>(stride_Q) = 0;
261	      get<2, 1>(stride_K) = 0;
262	      get<2, 1>(stride_V) = 0;
263	      get<2, 1>(stride_O) = 0;
264	      get<1, 1>(stride_LSE) = 0;
265	    }
266	
267	    typename Operation::Arguments arguments =
268	        get_arguments(problem_shape, hw_info, scale_softmax, q.data_ptr(), k.data_ptr(),
269	                      v.data_ptr(), o.data_ptr(), lse.data_ptr(),
270	                      cumulative_seqlen_q.data_ptr(), cumulative_seqlen_kv.data_ptr());
271	
272	    Operation op;
273	
274	    // size_t workspace_size = 0;
275	    // workspace_size = Operation::get_workspace_size(arguments);
276	
277	    // todo: if use workspace, need check workspace size first.
278	    // we don't use workspace in current version.
279	
280	    CUTLASS_CHECK(op.can_implement(arguments));
281	    CUTLASS_CHECK(op.initialize(arguments, nullptr));
282	    CUTLASS_CHECK(op.run(at::cuda::getCurrentCUDAStream()));
283	  }
284	};
285	
286	template <class DTypeIn, class DTypeOut, bool kIsVarlen, bool kIsMla, class ActiveMask,
287	          class... KernelOptions>
288	void run_fmha_fwd(at::Tensor workspace, at::Tensor q, at::Tensor k, at::Tensor v,
289	                  at::Tensor cumulative_seqlen_q, at::Tensor cumulative_seqlen_kv, at::Tensor o,
290	                  at::Tensor lse, float scale_softmax, int max_seqlen_q, int max_seqlen_kv) {
291	
292	  const at::cuda::CUDAGuard device_guard{(char)q.get_device()};
293	  const int device_id = q.get_device();
294	
295	  cutlass::KernelHardwareInfo hw_info;
296	  hw_info.device_id = device_id;
297	  hw_info.sm_count =
298	      cutlass::KernelHardwareInfo::query_device_multiprocessor_count(hw_info.device_id);
299	
300	  auto get_options = [&]() {
301	    if constexpr (kIsMla) {
302	      MlaOptions options;
303	      options.b = cumulative_seqlen_q.size(0) - 1;
304	      options.h = q.size(1);
305	      options.h_k = k.size(1);
306	      options.q = q.size(0) / options.b;
307	      options.k = k.size(0) / options.b;
308	      options.dl = v.size(-1);
309	      options.dr = q.size(-1) - v.size(-1);
310	      return options;
311	    } else {
312	      FmhaOptions options;
313	      options.b = cumulative_seqlen_q.size(0) - 1;
314	      options.h = q.size(1);
315	      options.h_k = k.size(1);
316	      options.q = q.size(0) / options.b;
317	      options.k = k.size(0) / options.b;
318	      options.d = q.size(-1);
319	      return options;
320	    }
321	  };
322	
323	  auto options = get_options();
324	
325	  if (options.h % cutlass::fmha::kernel::CausalIndividualTileScheduler::TileH == 0 &&
326	      (std::is_same_v<ActiveMask, CausalMask<false>> || std::is_same_v<ActiveMask, CausalMask<true>>)) {
327	    FwdRunner<kIsMla, true, kIsVarlen, DTypeIn, DTypeOut, ActiveMask, KernelOptions...> runner;
328	    runner.run(options, hw_info, q, k, v, o, lse, scale_softmax, workspace, cumulative_seqlen_q,
329	               cumulative_seqlen_kv, max_seqlen_q, max_seqlen_kv);
330	  } else {
331	    FwdRunner<kIsMla, false, kIsVarlen, DTypeIn, DTypeOut, ActiveMask, KernelOptions...> runner;
332	    runner.run(options, hw_info, q, k, v, o, lse, scale_softmax, workspace, cumulative_seqlen_q,
333	               cumulative_seqlen_kv, max_seqlen_q, max_seqlen_kv);
334	  }
335	}
