87	  template <class BlkCoord, class TileShape, class ProblemSize>
88	  CUTLASS_DEVICE int get_masked_trip_count(
89	      BlkCoord const& blk_coord,
90	      TileShape const& tile_shape,
91	      ProblemSize const& problem_size) {
92	
93	    if (get<1>(problem_size) % get<1>(tile_shape) != 0) {
94	      return 1;
95	    }
96	    return 0;
97	  }
98	
99	  template<class BlkCoord, class TileShape, class ProblemSize>
100	  CUTLASS_DEVICE
101	  int get_unmasked_trip_count(
102	      BlkCoord const& blk_coord,
103	      TileShape const& tile_shape,
104	      ProblemSize const& problem_size) {
105	
106	    // if the sequence length does not divide the tile size evenly
107	    if (get<1>(problem_size) % get<1>(tile_shape) != 0) {
108	      return get_trip_count(blk_coord, tile_shape, problem_size) - 1;
109	    }
110	    return get_trip_count(blk_coord, tile_shape, problem_size);
111	  }
