279	template<bool kIsQBegin = true>
280	struct CausalForBackwardMask : CausalMask<kIsQBegin>, ResidualMaskForBackward {
281	
282	  using Base = CausalMask<kIsQBegin>;
283	
284	  template<class AccQK, class IndexQK, class ProblemSize>
285	  CUTLASS_DEVICE
286	  void apply_mask(
287	      AccQK& acc_qk,
288	      IndexQK const& index_qk,
289	      ProblemSize const& problem_size) {
290	
291	    // There are two ways to do causal if N_Q != N_K
292	    // (1) is to assume that the Q is at the beginning of the matrix
293	    //    - this is what we demonstrate here
294	    // (2) is that it is at the end of the matrix
295	    //    - this is usually what we want for inference settings
296	    //      where we only compute the next row and use cache for the rest
297	    //    - if you'd like this, you only need to add an offset like so:
298	    //      get<0>(pos) + offset_q < get<1>(pos)
299	    int offset_q = 0;
300	    if constexpr (!kIsQBegin) {
301	      offset_q = get<1>(problem_size) - get<0>(problem_size);
302	    }
303	
304	    CUTLASS_PRAGMA_UNROLL
305	    for (int i = 0; i < size(acc_qk); i++) {
306	      auto pos = index_qk(i);
307	      bool masked = (get<0>(pos) + offset_q < get<1>(pos)) || !elem_less(pos, problem_size);
308	      if (masked) {
309	        acc_qk(i) = -INFINITY;
310	      }
311	    }
312	  }
313	
314	};
