123	    auto cluster_layout = make_layout(cluster_shape);
124	    if (mcast_direction == McastDirection::kRow) {
125	      block_id_mask_ = detail::calculate_multicast_mask<McastDirection::kRow>(cluster_shape, AtomThrShape_MNK{}, block_id_in_cluster);
126	    }
