153	  CUTLASS_DEVICE
154	  PipelineTmaAsyncMla(SharedStorage& storage, Params params, ClusterShape cluster_shape, McastDirection mcast_direction, InitBarriers = {}, InitMasks = {})
155	      : impl_(storage, params, cluster_shape, cute::false_type{}, cute::false_type{})
156	      , params_(params)
157	      , empty_barrier_ptr_(&storage.empty_barrier_[0])
158	      , full_barrier_ptr_(&storage.full_barrier_[0]) {
159	    static_assert(cute::is_same_v<InitBarriers, cute::true_type> || cute::is_same_v<InitBarriers, cute::false_type>);
160	    if constexpr (cute::is_same_v<InitBarriers, cute::true_type>) {
161	      init_barriers(storage, params_, cluster_shape, mcast_direction);
162	    }
163	
164	    static_assert(cute::is_same_v<InitMasks, cute::true_type> || cute::is_same_v<InitMasks, cute::false_type>);
165	    if constexpr (cute::is_same_v<InitMasks, cute::true_type>) {
166	      init_masks(cluster_shape, mcast_direction);
167	    }
