224	  static constexpr bool is_2sm_mma = size(AtomThrShape_MNK{}) > 1;
225	
226	  // Consumer signalling Producer of completion
227	  // Ensures all blocks in the Same Row and Column get notifed.
228	  CUTLASS_DEVICE
229	  void consumer_release(uint32_t stage, uint32_t skip) {
230	    detail::pipeline_check_is_consumer(params_.role);
231	    uint64_t* smem_ptr = reinterpret_cast<uint64_t*>(&empty_barrier_ptr_[stage]);
232	    if constexpr (is_2sm_mma) { // Mma cluster shape is 2x1
233	      if (!skip) {
234	        cutlass::arch::umma_arrive_multicast_2x1SM(smem_ptr, block_id_mask_);
235	      }
236	    }
237	    else {
238	      if (!skip) {
239	        if constexpr (cute::is_static_v<ClusterShape> and size(ClusterShape{}) == 1) {
240	          cutlass::arch::umma_arrive(smem_ptr);
241	        }
242	        else {
243	          cutlass::arch::umma_arrive_multicast(smem_ptr, block_id_mask_);
244	        }
245	      }
