55	template <class Kernel_>
56	class FMHA {
57	public:
58	  using Kernel = Kernel_;
59	
60	  static int const kThreadCount = Kernel::MaxThreadsPerBlock;
61	
62	  /// Argument structure: User API
63	  using Arguments = typename Kernel::Arguments;
64	  /// Argument structure: Kernel API
